mapper.select:
SELECT g.guest_id, g.name, g.status, r.room_number, SUM(CASE WHEN d.type IN ('收取','追加') THEN d.amount ELSE 0 END) - SUM(CASE WHEN d.type = '退还' THEN ABS(d.amount) ELSE 0 END) AS deposit_balance, MAX(d.create_time) AS last_operate_time FROM deposit d JOIN guest g ON d.guest_id = g.guest_id LEFT JOIN room r ON g.room_id = r.room_id WHERE 1=1
AND DATE(d.create_time) >= #{startDate}
AND DATE(d.create_time) <= #{endDate}
AND (g.name LIKE CONCAT('%', #{keyword}, '%') OR r.room_number LIKE CONCAT('%', #{keyword}, '%'))
AND g.status = #{status}
GROUP BY g.guest_id, g.name, g.status, r.room_number ORDER BY FIELD(g.status, '在住', '已离店'), last_operate_time DESC
